import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def waiting_penalty(arrive_time, window):
        if arrive_time < window[0]:
            return window[0] - arrive_time
        return 0

    costs = []
    for i, customer_pos in enumerate(unvisited_customers):
        tt = travel_time(cur_truck_pos, customer_pos)
        arrival = current_time + tt
        wait_pen = waiting_penalty(arrival, time_windows[i])
        total_time = tt + wait_pen
        costs.append(total_time)

    # Cooperative weight calculation
    cooperative_weights = []
    for i in range(len(unvisited_customers)):
        other_trucks_future_costs = 0
        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                other_trucks_future_costs += travel_time(truck_pos, unvisited_customers[i])
        cooperative_weights.append(costs[i] / (other_trucks_future_costs + 1))  # smoothing by adding 1 to avoid division by zero

    # Select best node based on smallest cooperative weight
    best_node = np.argmin(cooperative_weights)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    best_node = None
    highest_score = -np.inf

    for i, customer_pos in enumerate(unvisited_customers):
        time_to_customer = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + time_to_customer
        time_window_start, time_window_end = time_windows[i]

        if arrival_time > time_window_end:
            continue  # Skip if we cannot meet the time window

        # Calculate score based on remaining time and distance
        remaining_time = max(time_window_start - arrival_time, 0) + (time_window_end - arrival_time)
        score = 1 / (remaining_time + 1) + 1 / (time_to_customer + 1)  # Adding 1 to avoid division by zero

        # If customer can be reached within time window, prefer closer and urgent customers
        if score > highest_score:
            highest_score = score
            best_node = i

    if best_node is None and len(unvisited_customers) > 0:
        # If no timely reachable customer, recommend waiting (or could implement a fallback strategy)
        return None

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(p1, p2):
        return np.linalg.norm(p1 - p2) / truck_speed

    def urgency(time_window, arrival_time):
        start_window, end_window = time_window
        if arrival_time < start_window:
            return (start_window - arrival_time)  # early arrival urgency
        elif arrival_time > end_window:
            return (arrival_time - end_window) * 10  # late arrival much more urgent
        else:
            return 0  # within window

    min_cost = float('inf')
    best_node = None

    for idx, customer_pos in enumerate(unvisited_customers):
        time_window = time_windows[idx]
        travel_t = travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_t
        wait_or_penalty_time = urgency(time_window, arrival_time)

        cost = wait_or_penalty_time * travel_t  # Composite cost based on urgency and travel time

        # Minimize cost across all choices
        if cost < min_cost:
            min_cost = cost
            best_node = idx

    return best_node
